const WebSocket = require('ws');

const server = new WebSocket.Server({ port: 8080 });
const players = new Map();

server.on('connection', (ws) => {
  const playerId = generatePlayerId();
  players.set(playerId, { ws, units: [] });

  ws.on('message', (message) => {
    const command = JSON.parse(message);
    handleCommand(playerId, command);
  });

  ws.on('close', () => {
    players.delete(playerId);
  });
});

function generatePlayerId() {
  return 'player-' + Math.random().toString(36).substr(2, 9);
}

function handleCommand(playerId, command) {
  const player = players.get(playerId);
  if (!player) return;

  switch (command.type) {
    case 'build':
      buildStructure(player, command);
      break;
    case 'attack':
      attackTarget(player, command);
      break;
    case 'move':
      moveUnits(player, command);
      break;
  }
}

function buildStructure(player, command) {
  // Implement build logic
  console.log(`Player ${player} builds ${command.structure} at ${command.position}`);
}

function attackTarget(player, command) {
  // Implement attack logic
  console.log(`Player ${player} attacks ${command.target} with ${command.units}`);
}

function moveUnits(player, command) {
  // Implement move logic
  console.log(`Player ${player} moves units to ${command.destination}`);
}

